import toast from "react-hot-toast";
import { CheckCircle } from "lucide-react";

export const showAddSuccessToast = (linkName = "Link") => {
  toast.custom((t) => (
    <div
      className={`
        flex items-center gap-4
        px-5 py-4
        min-w-[320px]
        rounded-xl
        bg-[#0f172a]/95
        backdrop-blur-xl
        border border-blue-500/20
        shadow-[0_0_30px_rgba(59,130,246,0.15)]
        text-blue-100
        transition-all duration-300
        ${t.visible ? "opacity-100 translate-y-0" : "opacity-0 -translate-y-2"}
      `}
    >
      {/* Icon */}
      <div className="flex items-center justify-center w-10 h-10 rounded-lg bg-blue-500/10 border border-blue-500/30">
        <CheckCircle className="text-blue-400" size={20} />
      </div>

      {/* Text */}
      <div className="flex flex-col">
        <span className="text-sm font-semibold tracking-wide text-blue-200">
          Link Created Successfully
        </span>
        <span className="text-xs text-blue-300">
          "{linkName}" has been added
        </span>
      </div>
    </div>
  ), {
    duration: 2200,
    position: "top-right",
  });
};
